let mentorAssignments = clone(mentorAssignmentsSeed);
let reviewQueue = clone(reviewQueueSeed);
let projectReviews = clone(projectReviewsSeed);
let notifications = clone(notificationsSeed);

function clone(value) {
  return JSON.parse(JSON.stringify(value));
}

function waitForMock(payload, delay = REQUEST_DELAY_MS) {
  return new Promise((resolve) => {
    globalThis.setTimeout(() => resolve(clone(payload)), delay);
  });
}

function normalize(value) {
  return String(value || '').trim().toLowerCase();
}

function countBy(items, fieldName) {
  return items.reduce((accumulator, item) => {
    const key = item[fieldName] || 'UNKNOWN';
    accumulator[key] = (accumulator[key] || 0) + 1;
    return accumulator;
  }, {});
}

function getActiveUserCount() {
  return mockUsers.filter((user) => user.status === 'ACTIVE').length;
}

function getPendingReviewCount() {
  return reviewQueue.filter((submission) => submission.status === 'PENDING').length;
}

function getReviewResultSummary() {
  const reviewedCounts = countBy(projectReviews, 'result');
  return {
    totalReviewed: projectReviews.length,
    pass: reviewedCounts.PASS || 0,
    fail: reviewedCounts.FAIL || 0,
    pending: getPendingReviewCount(),
  };
}

function getMentorPerformanceRows() {
  const mentors = mockUsers.filter((user) => user.role === 'MENTOR');

  return mentors.map((mentor) => {
    const reviews = projectReviews.filter((review) => review.mentorId === mentor.id);
    const assignments = mentorAssignments.filter(
      (assignment) => assignment.mentorId === mentor.id && assignment.status === 'ACTIVE',
    );
    const pending = reviewQueue.filter(
      (submission) => submission.mentorId === mentor.id && submission.status === 'PENDING',
    ).length;

    return {
      mentorId: mentor.id,
      mentorName: mentor.name,
      activeAssignments: assignments.length,
      reviewed: reviews.length,
      pass: reviews.filter((review) => review.result === 'PASS').length,
      fail: reviews.filter((review) => review.result === 'FAIL').length,
      pending,
      averageHoursToReview: mentor.id === 'user-mentor-001' ? 18 : 26,
    };
  });
}

function buildDashboardPayload() {
  const reviewSummary = getReviewResultSummary();

  return {
    generatedAt: new Date().toISOString(),
    summary: {
      totalUsers: mockUsers.length,
      activeUsers: getActiveUserCount(),
      mentors: mockUsers.filter((user) => user.role === 'MENTOR').length,
      learners: mockUsers.filter((user) => user.role === 'LEARNER').length,
      activeAssignments: mentorAssignments.filter((assignment) => assignment.status === 'ACTIVE').length,
      pendingReviews: reviewSummary.pending,
      completedReviews: reviewSummary.totalReviewed,
      unreadNotifications: notifications.filter((notification) => !notification.isRead).length,
      revenueVnd: 18450000,
    },
    userStatus: countBy(mockUsers, 'status'),
    reviewSummary,
    mentorPerformance: getMentorPerformanceRows(),
    recentSubmissions: reviewQueue
      .filter((submission) => submission.status === 'PENDING')
      .sort((a, b) => new Date(b.submittedAt) - new Date(a.submittedAt))
      .slice(0, 4),
    recentReviews: projectReviews
      .slice()
      .sort((a, b) => new Date(b.reviewedAt) - new Date(a.reviewedAt))
      .slice(0, 4),
    notifications,
  };
}

function buildReportsPayload(range) {
  const reviewSummary = getReviewResultSummary();
  const mentorPerformance = getMentorPerformanceRows();
  const totalReviews = Math.max(reviewSummary.totalReviewed, 1);

  return {
    range,
    generatedAt: new Date().toISOString(),
    warnings: [
      {
        source: 'Payment adapter',
        code: 'MOCK_PARTIAL_DATA',
        message: 'Du lieu revenue dang la mock cho den khi Backend reports hoan thien.',
      },
    ],
    revenue: {
      totalVnd: 18450000,
      successfulPayments: 37,
      series: [
        { label: 'Tuan 1', value: 4200000 },
        { label: 'Tuan 2', value: 5100000 },
        { label: 'Tuan 3', value: 3900000 },
        { label: 'Tuan 4', value: 5250000 },
      ],
    },
    users: {
      total: mockUsers.length,
      active: getActiveUserCount(),
      byRole: countBy(mockUsers, 'role'),
      byStatus: countBy(mockUsers, 'status'),
      newUsers: 16,
    },
    courses: {
      totalCourses: 18,
      activeCourses: 14,
      completionRate: 68,
      topCourses: [
        { courseId: 'course-react-101', title: 'React Foundation', learners: 42, completionRate: 72 },
        { courseId: 'course-node-api', title: 'NodeJS REST API', learners: 35, completionRate: 64 },
        { courseId: 'course-ui-bootstrap', title: 'Bootstrap UI Practice', learners: 28, completionRate: 78 },
      ],
    },
    reviews: {
      ...reviewSummary,
      passRate: Math.round((reviewSummary.pass / totalReviews) * 100),
      failRate: Math.round((reviewSummary.fail / totalReviews) * 100),
      mentorPerformance,
    },
  };
}

export function __resetAdminMentorMockDataForTests() {
  mockUsers = clone(mockUsersSeed);
  mentorAssignments = clone(mentorAssignmentsSeed);
  reviewQueue = clone(reviewQueueSeed);
  projectReviews = clone(projectReviewsSeed);
  notifications = clone(notificationsSeed);
}

export const adminMentorApi = {
  // TODO: Thay bằng Axios/Fetch để gọi API thật khi Backend hoàn thiện.
  // Khi thay mock bằng request thật, cần dùng `credentials: 'include'` để đồng bộ JWT httpOnly Cookie từ Member 1.
  getAdminDashboard() {
    return waitForMock({ success: true, data: buildDashboardPayload() });
  },

  // TODO: Thay bằng Axios/Fetch để gọi API thật khi Backend hoàn thiện: GET /admin/users.
  async getAdminUsers({ search = '', role = 'ALL', status = 'ALL' } = {}) {
    const keyword = normalize(search);
    const users = mockUsers.filter((user) => {
      const matchesKeyword =
        !keyword || normalize(user.name).includes(keyword) || normalize(user.email).includes(keyword);
      const matchesRole = role === 'ALL' || user.role === role;
      const matchesStatus = status === 'ALL' || user.status === status;

      return matchesKeyword && matchesRole && matchesStatus;
    });

    return waitForMock({ success: true, data: users });
  },

  // Mock write action cho User Management UI. Backend thật phải enforce Auth/Admin rule và audit log.
  async updateUserStatus(userId, nextStatus) {
    const user = mockUsers.find((item) => item.id === userId);
    if (!user) {
      return Promise.reject({ success: false, code: 'NOT_FOUND', message: 'Khong tim thay user.' });
    }

    user.status = nextStatus;
    return waitForMock({ success: true, data: user });
  },

  // TODO: Thay bằng Axios/Fetch để gọi API thật khi Backend hoàn thiện: GET /admin/reports.
  getAdminReports({ range = '30d' } = {}) {
    return waitForMock({ success: true, data: buildReportsPayload(range) });
  },

  getMentorDashboard() {
    const mentorId = 'user-mentor-001';
    const assignments = mentorAssignments.filter(
      (assignment) => assignment.mentorId === mentorId && assignment.status === 'ACTIVE',
    );
    const queue = reviewQueue.filter(
      (submission) => submission.mentorId === mentorId && submission.status === 'PENDING',
    );
    const reviews = projectReviews.filter((review) => review.mentorId === mentorId);

    return waitForMock({
      success: true,
      data: {
        mentorId,
        assignments,
        queue,
        reviews,
        summary: {
          activeAssignments: assignments.length,
          pendingReviews: queue.length,
          completedReviews: reviews.length,
          passReviews: reviews.filter((review) => review.result === 'PASS').length,
          failReviews: reviews.filter((review) => review.result === 'FAIL').length,
        },
      },
    });
  },

  // TODO: Thay bằng Axios/Fetch để gọi API thật khi Backend hoàn thiện: GET /mentor/review-queue.
  async getMentorReviewQueue({ search = '', courseId = 'ALL' } = {}) {
    const keyword = normalize(search);
    const submissions = reviewQueue.filter((submission) => {
      const matchesKeyword =
        !keyword ||
        normalize(submission.learnerName).includes(keyword) ||
        normalize(submission.courseTitle).includes(keyword);
      const matchesCourse = courseId === 'ALL' || submission.courseId === courseId;

      return submission.status === 'PENDING' && matchesKeyword && matchesCourse;
    });

    return waitForMock({ success: true, data: submissions });
  },

  getReviewSubmission(submissionId) {
    const submission = reviewQueue.find((item) => item.id === submissionId);
    if (!submission) {
      return Promise.reject({
        success: false,
        code: 'SUBMISSION_NOT_FOUND',
        message: 'Khong tim thay bai nop can cham.',
      });
    }

    return waitForMock({ success: true, data: submission });
  },

  // TODO: Thay bằng Axios/Fetch để gọi API thật khi Backend hoàn thiện: POST /reviews/:id.
  async submitReview(submissionId, { result, feedback }) {
    const submission = reviewQueue.find((item) => item.id === submissionId);
    if (!submission) {
      return Promise.reject({
        success: false,
        code: 'SUBMISSION_NOT_FOUND',
        message: 'Khong tim thay bai nop can cham.',
      });
    }

    if (!['PASS', 'FAIL'].includes(result) || normalize(feedback).length < 10) {
      return Promise.reject({
        success: false,
        code: 'VALIDATION_ERROR',
        message: 'Ket qua hoac feedback khong hop le.',
      });
    }

    // Logic mock nay gia lap transaction backend: review, feedback va submission status phai doi cung nhau.
    submission.status = 'REVIEWED';
    const nextReview = {
      id: `review-${String(projectReviews.length + 1).padStart(3, '0')}`,
      submissionId,
      mentorId: submission.mentorId,
      mentorName: 'Nguyen Thanh Mentor',
      learnerName: submission.learnerName,
      courseTitle: submission.courseTitle,
      result,
      feedback,
      reviewedAt: new Date().toISOString(),
    };
    projectReviews = [nextReview, ...projectReviews];

    return waitForMock({ success: true, data: nextReview });
  },
};
